import{_ as n,C as s,o as t,c as i,a2 as r,b as d,w as o,a as l,E as g,a3 as c}from"./chunks/framework._O8Cueap.js";const S=JSON.parse('{"title":"System Overview","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/overview.md","filePath":"architecture/overview.md"}'),A={name:"architecture/overview.md"};function h(I,e,C,u,p,m){const a=s("Mermaid");return t(),i("div",null,[e[1]||(e[1]=r('<h1 id="system-overview" tabindex="-1">System Overview <a class="header-anchor" href="#system-overview" aria-label="Permalink to &quot;System Overview&quot;">​</a></h1><p>Open Agent Orchestra (OAO) is an autonomous AI workflow engine. It can be deployed on Docker, Kubernetes, or a standalone VM — the architecture is runtime-agnostic.</p><h2 id="components-ports" tabindex="-1">Components &amp; Ports <a class="header-anchor" href="#components-ports" aria-label="Permalink to &quot;Components &amp; Ports&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Role</th><th>Default Port</th><th>Scalable</th></tr></thead><tbody><tr><td><strong>OAO-API</strong></td><td>Stateless REST API serving all client requests</td><td>4002</td><td>Yes (horizontal)</td></tr><tr><td><strong>OAO-UI</strong></td><td>Dashboard (Nuxt 3 SSR) for managing the platform</td><td>3002</td><td>Yes (horizontal)</td></tr><tr><td><strong>OAO-Controller</strong></td><td>Trigger poller + workflow dispatcher (leader-elected)</td><td>—</td><td>Yes (HA standby)</td></tr><tr><td><strong>Static Agent Worker</strong></td><td>Long-running BullMQ consumer for step execution</td><td>—</td><td>Yes (horizontal)</td></tr><tr><td><strong>Ephemeral Agent Instance</strong></td><td>Short-lived K8s pod per step (K8s only)</td><td>—</td><td>Yes, when a workflow selects <code>ephemeral</code> runtime</td></tr><tr><td><strong>PostgreSQL</strong></td><td>Persistent storage + pgvector embeddings</td><td>5432</td><td>External / managed</td></tr><tr><td><strong>Redis</strong></td><td>Job queues (BullMQ) + leader lock + semaphore</td><td>6379</td><td>External / managed</td></tr></tbody></table><p>All backend services (API, Controller, Agent Worker) run from a <strong>single Docker image</strong> (<code>oao-core</code>). The role is selected by the container&#39;s entrypoint command — no separate build is needed for each component.</p><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">​</a></h2><p><strong>Why separate components?</strong></p><table tabindex="0"><thead><tr><th>Principle</th><th>How OAO applies it</th></tr></thead><tbody><tr><td><strong>Scalability</strong></td><td>API scales independently from the Controller and Agent Workers. Stateless API pods can be auto-scaled based on request load, while agent workers scale based on queue depth.</td></tr><tr><td><strong>Resilience</strong></td><td>If an agent worker crashes mid-step, the Controller detects the failure and marks the step as failed — other workers and the API are unaffected. Leader election ensures the Controller has automatic failover.</td></tr><tr><td><strong>Static vs Dynamic Workload</strong></td><td>API/UI traffic is predictable (human-driven). Agent workload is bursty (batch workflows, cron triggers). Separating them prevents AI workloads from starving HTTP responses.</td></tr><tr><td><strong>Security Isolation</strong></td><td>Only the Controller needs Kubernetes RBAC (for ephemeral pods). Agent workers only need database + Redis + GitHub token access. The API never executes AI sessions directly.</td></tr><tr><td><strong>Single Image, Multiple Roles</strong></td><td>One <code>oao-core</code> image reduces build time, avoids image drift, and simplifies registry management. Runtime command selects the process.</td></tr></tbody></table><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to &quot;High-Level Architecture&quot;">​</a></h2>',9)),(t(),d(c,null,{default:o(()=>[g(a,{id:"mermaid-193",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%22Frontend%22%0A%20%20%20%20%20%20%20%20UI%5BOAO-UI%3Cbr%2F%3E%3A3002%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Backend%22%0A%20%20%20%20%20%20%20%20API%5BOAO-API%3Cbr%2F%3E%3A4002%5D%0A%20%20%20%20%20%20%20%20CTRL%5BOAO-Controller%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Agent%20Instances%22%0A%20%20%20%20%20%20%20%20SA1%5B%22Static%20Worker%201%22%5D%0A%20%20%20%20%20%20%20%20SA2%5B%22Static%20Worker%202%22%5D%0A%20%20%20%20%20%20%20%20EA1%5B%22Ephemeral%20Instance%3Cbr%2F%3E(K8s%20only)%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Data%20Layer%22%0A%20%20%20%20%20%20%20%20PG%5B(PostgreSQL%3Cbr%2F%3E%3A5432)%5D%0A%20%20%20%20%20%20%20%20RD%5B(Redis%3Cbr%2F%3E%3A6379)%5D%0A%20%20%20%20%20%20%20%20WQ%5B%22workflow-execution%3Cbr%2F%3Equeue%22%5D%0A%20%20%20%20%20%20%20%20SQ%5B%22agent-step-execution%3Cbr%2F%3Equeue%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22External%22%0A%20%20%20%20%20%20%20%20GH%5BGitHub%20Copilot%20SDK%5D%0A%20%20%20%20%20%20%20%20MCP%5BMCP%20Servers%5D%0A%20%20%20%20%20%20%20%20GIT%5BGit%20Repos%5D%0A%20%20%20%20end%0A%0A%20%20%20%20UI%20--%3E%7CREST%20API%7C%20API%0A%20%20%20%20API%20--%3E%20PG%0A%20%20%20%20API%20--%3E%7C%22emit%20events%22%7C%20PG%0A%20%20%20%20CTRL%20--%3E%7C%22poll%20triggers%20%2B%20events%22%7C%20PG%0A%20%20%20%20CTRL%20--%3E%7C%22enqueue%22%7C%20WQ%0A%20%20%20%20WQ%20--%3E%20CTRL%0A%20%20%20%20CTRL%20--%3E%7C%22enqueue%20steps%20(static)%22%7C%20SQ%0A%20%20%20%20CTRL%20--%3E%7C%22create%20pods%20(ephemeral)%22%7C%20EA1%0A%20%20%20%20SQ%20--%3E%20SA1%0A%20%20%20%20SQ%20--%3E%20SA2%0A%20%20%20%20SA1%20--%3E%20PG%0A%20%20%20%20SA1%20--%3E%20GH%0A%20%20%20%20SA1%20--%3E%20MCP%0A%20%20%20%20EA1%20--%3E%20PG%0A%20%20%20%20EA1%20--%3E%20GH%0A%20%20%20%20CTRL%20-.-%3E%7C%22leader%20lock%22%7C%20RD%0A%20%20%20%20WQ%20-.-%3E%20RD%0A%20%20%20%20SQ%20-.-%3E%20RD%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=r('<div class="mermaid-source" data-mermaid-source=""></div><p>All trigger types — cron, datetime, webhook, event, and Manual Run — flow through the Controller via <code>system_events</code>.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><h3 id="oao-api" tabindex="-1">OAO-API <a class="header-anchor" href="#oao-api" aria-label="Permalink to &quot;OAO-API&quot;">​</a></h3><p>The stateless REST API serving all client requests:</p><ul><li><strong>Authentication</strong> — JWT (HS256, 7-day expiry) with workspace context</li><li><strong>Routes</strong> — Agents, Workflows, Triggers, Executions, Variables, Instances, Admin, Events, Webhooks, Tokens</li><li><strong>Validation</strong> — Zod schemas on all inputs</li><li><strong>Security</strong> — AES-256-GCM encryption for credentials, HMAC-SHA256 webhooks, PAT with fine-grained scopes</li><li><strong>Event emission</strong> — All mutations emit <code>system_events</code> for audit and trigger matching</li></ul><h3 id="oao-ui" tabindex="-1">OAO-UI <a class="header-anchor" href="#oao-ui" aria-label="Permalink to &quot;OAO-UI&quot;">​</a></h3><p>The dashboard for managing the platform:</p><ul><li>Agent configuration, workflow design, execution monitoring</li><li>Agent instance monitoring (Static + Ephemeral)</li><li>Variable management, admin controls</li><li>JWT auth with middleware guards; all <code>/api/*</code> proxied to OAO-API</li></ul><h3 id="oao-controller" tabindex="-1">OAO-Controller <a class="header-anchor" href="#oao-controller" aria-label="Permalink to &quot;OAO-Controller&quot;">​</a></h3><p>A long-running process that manages triggers and dispatches work. Runs as a container (Docker/K8s) or a standalone process:</p><table tabindex="0"><thead><tr><th>Sub-component</th><th>Role</th></tr></thead><tbody><tr><td><strong>Leader Election</strong></td><td>Redis <code>SETNX</code> with 60s TTL — only one instance polls; others are standby</td></tr><tr><td><strong>Trigger Poller</strong></td><td>Polls PostgreSQL for due triggers and new <code>system_events</code></td></tr><tr><td><strong>BullMQ Worker</strong></td><td>Dequeues workflow jobs. Dispatches steps to static workers (via queue) or ephemeral instances (via K8s API) based on the workflow&#39;s <code>workerRuntime</code>.</td></tr></tbody></table><p><strong>Scaling:</strong> Deploy multiple controller replicas for HA. Leader election ensures exactly one polls. BullMQ&#39;s atomic dequeue prevents duplicates.</p><p>For more details on agent instances (static vs ephemeral), scaling strategy, and Docker image roles, see <a href="/open-agent-orchestra/architecture/agent-instances.html">Agent Instances</a>.</p><p>For request and trigger flow diagrams, see <a href="/open-agent-orchestra/architecture/request-flows.html">Request &amp; Trigger Flows</a>.</p>',15))])}const E=n(A,[["render",h]]);export{S as __pageData,E as default};
